mapper.select:
select 
from doctor_schedule s
         left join doctor_info d on s.doctor_id = d.id
         left join department_info dp on s.department_id = dp.id


        and s.department_id = #{departmentId}


        and s.doctor_id = #{doctorId}


        and s.status = #{status}


        and s.schedule_date = #{scheduleDate}


order by s.schedule_date desc, s.id desc

select 
from doctor_schedule s
         left join doctor_info d on s.doctor_id = d.id
         left join department_info dp on s.department_id = dp.id
where s.doctor_id = #{doctorId}

    and s.status = #{status}


    and s.schedule_date = #{scheduleDate}

order by s.schedule_date desc, s.id desc

select 
from doctor_schedule s
         left join doctor_info d on s.doctor_id = d.id
         left join department_info dp on s.department_id = dp.id
where s.status = 1 and s.remaining_source > 0

    and s.department_id = #{departmentId}


    and s.doctor_id = #{doctorId}


    and s.schedule_date = #{scheduleDate}

order by s.schedule_date asc, s.id desc
